// Instrument copy events on response content
// Fired when user copies text from a model response

document.addEventListener('copy', (event) => {
  const selection = window.getSelection()?.toString() || '';
  const responseElement = event.target?.closest('[data-response-id]');
  if (!responseElement) return;  // Copy from elsewhere in the page

  const responseId = responseElement.dataset.responseId;
  const selectionLength = selection.length;
  const isFullResponse = selectionLength >= (responseElement.textContent?.length ?? 0) * 0.9;

  // Send telemetry (not the copied content — just the metadata)
  navigator.sendBeacon('/api/telemetry/copy-event', JSON.stringify({
    responseId,
    selectionLength,
    isFullResponse,
    sessionId: window.__sessionId,
    timestamp: new Date().toISOString(),
  }));
});
